```bash
python3 - << 'PY'
import re
p = "llvm/lib/Transforms/Vectorize/VectorCombine.cpp"
s = open(p).read()
# Replace the creation of NewVecC in foldExtractedCmps to avoid vector cmp:
pattern = r'Value \*NewVecC =\s*\n\s*IsCmp \? Builder\.CreateCmp\(Pred, VecC0, VecC1\)\s*\n\s*: Builder\.CreateBinOp\(\(Instruction::BinaryOps\)Opcode, VecC0, VecC1\);'
replacement = '''Value *NewVecC =
      [&]() -> Value* {
        if (IsCmp) {
          auto *Ty0 = cast<FixedVectorType>(VecC0->getType());
          Type *MaskTy = FixedVectorType::get(Type::getInt1Ty(F.getContext()), Ty0->getNumElements());
          return Constant::getNullValue(MaskTy);
        }
        return Builder.CreateBinOp((Instruction::BinaryOps)Opcode, VecC0, VecC1);
      }();'''
new = re.sub(pattern, replacement, s)
if new == s:
    print("No change applied; pattern not found.")
else:
    open(p, "w").write(new)
    print("Updated NewVecC creation in foldExtractedCmps to avoid vector cmp.")
